import { test, expect } from '@playwright/test';
import { fileURLToPath } from 'url';
import path from 'path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/async_page.html')}`;

test.describe('Async Page Tests', () => {
    test.beforeEach(async ({ page }) => {
        await page.goto(localUrl);
    });

  test('should have correct page title', async ({ page }) => {
    await expect(page).toHaveTitle('Async Page — AutoHeal Demo');
  });

  test('button should be initially hidden', async ({ page }) => {
    const lateButton = page.getByRole('button', { name: 'Click Me Finally' });
    await expect(lateButton).toBeHidden();
  });

  test('button should become visible after 1200ms delay', async ({ page }) => {
    const lateButton = page.getByRole('button', { name: 'Click Me Finally' });
    await expect(lateButton).toBeVisible({ timeout: 5000 });
  });

  test('button should be clickable when visible', async ({ page }) => {
      // Config injection fix: increasing timeouts directly for this test
      test.setTimeout(120000);
      await page.goto(localUrl, { timeout: 120000 });
      const lateButton = page.getByRole('button', { name: 'Click Me Finally' });
      await lateButton.waitFor({ state: 'visible' });
      await expect(lateButton).toBeEnabled();
      await lateButton.click();
  });
});
